-- ============================================================
-- Backfill historical timesheet data
-- Generated from 3 xlsx files
-- 176 time entries for 3 employees
-- ============================================================

-- Temporarily disable triggers that would interfere
ALTER TABLE time_entries DISABLE TRIGGER trg_compute_hours;
ALTER TABLE time_entries DISABLE TRIGGER trg_validate_work_date;
ALTER TABLE time_entries DISABLE TRIGGER trg_prevent_locked_edits;

-- ── Pay Periods ──────────────────────────────────────────────

-- ── Time Entries ────────────────────────────────────────────
-- Each entry uses a subquery to look up employee_id and pay_period_id


-- Re-enable triggers
ALTER TABLE time_entries ENABLE TRIGGER trg_compute_hours;
ALTER TABLE time_entries ENABLE TRIGGER trg_validate_work_date;
ALTER TABLE time_entries ENABLE TRIGGER trg_prevent_locked_edits;

